//! Binary-level integration tests for `baton-do`.
//!
//! Spawns the compiled `baton-do` binary, pipes one or more NDJSON
//! envelopes into stdin, and asserts on the parsed output. Together
//! these tests cover all 11 operations end-to-end through the full
//! pipeline (clap front end → NDJSON loop → envelope deserialiser →
//! dispatcher → operations layer → wire-format output) plus the
//! binary-only concerns the dispatcher tests can't reach: the
//! `--no-error` exit-code policy, `--file` input source, the
//! parse-failure annotation path, and multi-record streaming.

use std::io::Write;
use std::process::{Command, Output, Stdio};

use baton_rs::types::{
    Arguments, Avu, AvuQuery, BatonDoEnvelope, BatonDoOutput, Collection, DataObject,
    MetaqueryInput, Operation, OperationResult, Operator, Target,
};
use baton_rs::Acl;
use serde_json::Value;

const TEST_COLL: &str = "/testZone/home/irods";

fn baton_do_path() -> &'static str {
    env!("CARGO_BIN_EXE_baton-do")
}

/// Spawn `baton-do` with `args`, write `input` to stdin, return the
/// completed process output (stdout / stderr / exit status). Spawn
/// failures panic — those are test-setup faults, not behaviour.
fn run_baton_do(args: &[&str], input: &str) -> Output {
    let mut child = Command::new(baton_do_path())
        .args(args)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .expect("spawn baton-do");

    child
        .stdin
        .as_mut()
        .expect("stdin handle")
        .write_all(input.as_bytes())
        .expect("write stdin");

    child.wait_with_output().expect("wait_with_output")
}

fn stdout_str(output: &Output) -> String {
    String::from_utf8(output.stdout.clone()).expect("stdout utf-8")
}

fn parse_outputs(stdout: &str) -> Vec<BatonDoOutput> {
    stdout
        .lines()
        .filter(|l| !l.trim().is_empty())
        .map(|l| {
            serde_json::from_str::<BatonDoOutput>(l)
                .unwrap_or_else(|e| panic!("parse output {:?}: {}", l, e))
        })
        .collect()
}

fn parse_value_lines(stdout: &str) -> Vec<Value> {
    stdout
        .lines()
        .filter(|l| !l.trim().is_empty())
        .map(|l| serde_json::from_str::<Value>(l).unwrap_or_else(|e| panic!("parse {:?}: {}", l, e)))
        .collect()
}

fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

fn imkdir(remote: &str) {
    let status = Command::new("imkdir")
        .args(["-p", remote])
        .status()
        .expect("spawn imkdir");
    assert!(status.success(), "imkdir {} failed", remote);
}

fn imeta_add_data_object(path: &str, attr: &str, value: &str) {
    let status = Command::new("imeta")
        .args(["add", "-d", path, attr, value])
        .status()
        .expect("spawn imeta");
    assert!(status.success(), "imeta add -d {} failed", path);
}

/// `irm -r -f` cleans both data objects and (populated) collections.
struct IrodsCleanup(String);
impl Drop for IrodsCleanup {
    fn drop(&mut self) {
        let _ = Command::new("irm").args(["-r", "-f", &self.0]).status();
    }
}

fn data_object_target(collection: &str, data_object: &str) -> Target {
    Target::DataObject(DataObject {
        collection: collection.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    })
}

fn collection_target(collection: &str) -> Target {
    Target::Collection(Collection {
        collection: collection.to_string(),
        avus: None,
        access: None,
        timestamps: None,
        contents: None,
        error: None,
    })
}

fn unique_name(prefix: &str) -> String {
    format!("{}_{}", prefix, std::process::id())
}

fn assert_success_exit(output: &Output) {
    assert!(
        output.status.success(),
        "baton-do exit non-zero: status={:?}\nstdout={}\nstderr={}",
        output.status,
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr),
    );
}

fn one_envelope_line(env: BatonDoEnvelope) -> String {
    let mut s = serde_json::to_string(&env).expect("serialise envelope");
    s.push('\n');
    s
}

