// --- Binary-level concerns -----------------------------------------------

#[test]
fn no_error_flag_suppresses_nonzero_exit_on_per_input_error() {
    // Reference a non-existent data object to provoke an in-band
    // error; with --no-error the exit code stays 0, without it the
    // dispatcher's per-input failure should bubble up to exit 1.
    let missing = unique_name("baton_rs_bin_missing");
    let env = BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &missing),
        Arguments::default(),
    );
    let input = one_envelope_line(env);

    let without = run_baton_do(&[], &input);
    assert!(
        !without.status.success(),
        "in-band error should produce non-zero exit: stdout={}",
        stdout_str(&without),
    );

    let with = run_baton_do(&["--no-error"], &input);
    assert!(
        with.status.success(),
        "--no-error should force exit 0: status={:?}",
        with.status,
    );

    // Either way the in-band annotation is on the output line.
    let outputs = parse_outputs(&stdout_str(&with));
    assert_eq!(outputs.len(), 1);
    assert!(
        outputs[0].error.is_some(),
        "in-band error annotation should still be present with --no-error",
    );
}

#[test]
fn parse_failure_is_annotated_and_stream_continues() {
    // Two input lines: one unparseable, one a valid list envelope.
    // The malformed line emits a stand-alone {"error": ...} and the
    // good line still gets dispatched. Exit status is non-zero
    // because we had at least one error.
    let local = "/tmp/baton_rs_bin_parsefail_src";
    std::fs::write(local, b"binary parsefail").expect("write");
    let name = unique_name("baton_rs_bin_parsefail");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let good = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));
    let input = format!("not-json\n{}", good);

    let output = run_baton_do(&[], &input);
    assert!(
        !output.status.success(),
        "parse failure should produce non-zero exit",
    );

    let lines = parse_value_lines(&stdout_str(&output));
    assert_eq!(lines.len(), 2, "one parse-error line + one list line");
    assert!(
        lines[0].get("error").is_some(),
        "first line should be a stand-alone error: {}",
        lines[0],
    );
    // Second line is a fully-formed envelope.
    assert!(
        lines[1].get("operation").is_some(),
        "second line should be a normal output envelope: {}",
        lines[1],
    );
}

